-- LOCAL-ONLY seed generated from Laporan Stock Pangkalan Balai (OLAH)(1)(1).xlsx.
-- Source coverage: 2026-01-01 through 2026-07-01; 320 movements; 268 meter rows.
-- Workbook lacks capacity and FIFO cost. Capacity is observed maximum rounded up plus 1,000 L;
-- MIGRATION_UNCOSTED layers use zero as an explicit unknown-cost sentinel for local testing.

INSERT INTO branch (id, code, name, timezone) VALUES
  ('10000000-0000-0000-0000-000000000001', 'PBL', 'Pangkalan Balai', 'Asia/Jakarta')
ON CONFLICT (code) DO UPDATE SET name=EXCLUDED.name, timezone=EXCLUDED.timezone, active=true;

INSERT INTO product (id, code, name, unit) VALUES
  ('20000000-0000-0000-0000-000000000001', 'BBM', 'BBM', 'LITER')
ON CONFLICT (code) DO UPDATE SET name=EXCLUDED.name, unit=EXCLUDED.unit, active=true;

INSERT INTO stock_unit
  (id, branch_id, product_id, code, name, capacity_qty, low_stock_threshold_qty) VALUES
  ('30000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000001',
   '20000000-0000-0000-0000-000000000001', 'POMPA-DEPAN', 'Pompa Depan', 8000, 0),
  ('30000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000001',
   '20000000-0000-0000-0000-000000000001', 'POMPA-BELAKANG', 'Pompa Belakang', 6000, 0)
ON CONFLICT (branch_id, code) DO UPDATE SET
  name=EXCLUDED.name, capacity_qty=EXCLUDED.capacity_qty, active=true;

INSERT INTO meter_unit (id, branch_id, code, name) VALUES
  ('40000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000001', 'METER-DEPAN', 'Meter Pompa Depan'),
  ('40000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000001', 'METER-BELAKANG', 'Meter Pompa Belakang')
ON CONFLICT (branch_id, code) DO UPDATE SET name=EXCLUDED.name, active=true;

INSERT INTO meter_stock_assignment (meter_unit_id, stock_unit_id, valid_from)
SELECT meter_id, stock_id, '2026-01-01'::date FROM (VALUES
  ('40000000-0000-0000-0000-000000000001'::uuid, '30000000-0000-0000-0000-000000000001'::uuid),
  ('40000000-0000-0000-0000-000000000002'::uuid, '30000000-0000-0000-0000-000000000002'::uuid)
) AS assignment(meter_id, stock_id)
WHERE NOT EXISTS (
  SELECT 1 FROM meter_stock_assignment existing
  WHERE existing.meter_unit_id=assignment.meter_id AND existing.stock_unit_id=assignment.stock_id
    AND existing.valid_from='2026-01-01'::date
);

