INSERT INTO inventory_movement
  (branch_id, stock_unit_id, business_date, movement_type, quantity_delta, source_type,
   idempotency_key, reference, reason, posted_at, created_at)
SELECT '10000000-0000-0000-0000-000000000001', unit.id, source.business_date,
  source.movement_type, source.quantity_delta, 'XLSX_IMPORT', source.idempotency_key,
  'Laporan Stock Pangkalan Balai (OLAH)(1)(1).xlsx', 'Imported from sheet ' || source.sheet_name,
  source.business_date::timestamp + time '20:00', source.business_date::timestamp + time '20:00'
FROM source
JOIN stock_unit unit ON unit.branch_id='10000000-0000-0000-0000-000000000001'
  AND unit.code=CASE source.unit_code WHEN 'FRONT' THEN 'POMPA-DEPAN' ELSE 'POMPA-BELAKANG' END
ON CONFLICT (branch_id, idempotency_key) DO NOTHING;

