    AS row(unit_code text, business_date date, meter_start numeric, meter_end numeric,
      cash_deposit_amount numeric, note text, idempotency_key text)
)
INSERT INTO sales_meter_reading
  (branch_id, meter_unit_id, business_date, meter_start, meter_end, meter_reset_offset,
   cash_deposit_amount, note, reconciliation_status, posting_status, idempotency_key, posted_at, created_at)
SELECT '10000000-0000-0000-0000-000000000001', meter.id, source.business_date,
  source.meter_start, source.meter_end, 0, source.cash_deposit_amount, source.note,
  CASE WHEN source.meter_end=source.meter_start AND source.cash_deposit_amount=0
    THEN 'MATCHED'::reconciliation_status ELSE 'PENDING'::reconciliation_status END,
  'POSTED', source.idempotency_key, source.business_date::timestamp + time '20:00',
  source.business_date::timestamp + time '20:00'
FROM source
JOIN meter_unit meter ON meter.branch_id='10000000-0000-0000-0000-000000000001'
  AND meter.code=CASE source.unit_code WHEN 'FRONT' THEN 'METER-DEPAN' ELSE 'METER-BELAKANG' END
ON CONFLICT DO NOTHING;

